import java.util.*;

public int minCost(String sentence, int k) {
	String[] words = sentence.split(" ");
	int[] dp = new int[words.length + 1];
	Arrays.fill(dp, Integer.MAX_VALUE);
	dp[0] = 0;
	for (int i = 0; i < words.length; i++) {
		int length = 0;
		for (int j = i; j >= 0; j--) {
			length += words[j].length();
			if (length + (i - j) <= k) {
				dp[i + 1] = Math.min(dp[i + 1], dp[j] + (k - length - (i - j)) * (k - length - (i - j)));
			} else {
				break;
			}
			length += 1;
		}
	}
	return dp[dp.length - 1];
}
```


